const fs = require('node:fs');
const input = fs.readFileSync(0, 'utf8').trim();
class Counter{#value;constructor(value){this.#value=value}increment(){this.#value+=1}get value(){return this.#value}} const [start,steps]=input.split(/\s+/).map(Number); const counter=new Counter(start); for(let i=0;i<steps;i+=1)counter.increment(); console.log(counter.value);
